const findItem = function (bot, name) {
  return bot.inventory.items().find(function (item) {
    return item.name === name || (item.displayName && item.displayName.toLowerCase().includes(name));
  });
};

const bow = findItem(bot, args.weapon);
const arrows = findItem(bot, 'arrow');

if (!bow) {
  return "<ERROR>: No " + args.weapon + " found in inventory.";
}

if (!arrows) {
  return "<ERROR>: No arrows found in inventory.";
}

let targetEntity = null;
if (args.target_id) {
  targetEntity = bot.entities[args.target_id];
} else {
  targetEntity = bot.nearestEntity(function (e) {
    return (e.type === 'hostile' || e.type === 'mob') && e.health > 0;
  });
}

if (!targetEntity) {
  return "<CANCELLED>: No hostile target found nearby.";
}

const sleep = function (ms) { return new Promise(function (resolve) { setTimeout(resolve, ms); }); };

startBackgroundSkill(bot, 'ranged_attack_nearest_hostile', async function (token) {
  const movements = new Movements(bot);
  const checkStatus = function () {
    return !token.cancelled && bot.health > 0 && bot.entity && targetEntity && targetEntity.isValid && (targetEntity.health === undefined || targetEntity.health > 0);
  };

  while (checkStatus()) {
    if (!bot.physicsEnabled) {
      await sleep(100);
      continue;
    }

    const currentBow = findItem(bot, args.weapon);
    const currentArrows = findItem(bot, 'arrow');
    if (!currentBow || !currentArrows) break;

    await bot.equip(currentBow, 'hand');

    const dist = bot.entity.position.distanceTo(targetEntity.position);

    // Positioning logic: Maintain preferred distance
    if (dist > args.preferredDistance + 2 || dist < args.preferredDistance - 2) {
      bot.pathfinder.setMovements(movements);
      // GoalFollow tries to stay within a range. 
      // If we are too close, we use GoalAway if we find a custom implementation, 
      // otherwise we use follow with a range.
      bot.pathfinder.setGoal(new goals.GoalFollow(targetEntity, args.preferredDistance), true);
    } else {
      bot.pathfinder.setGoal(null);
    }

    // Attack logic: Charge, Aim, Fire
    bot.activateItem(); // Start drawing the bow
    const chargeStart = Date.now();

    // Wait for charge while tracking the target visually
    while (Date.now() - chargeStart < 1200 && checkStatus()) {
      // Aim slightly above center for gravity
      const aimPos = targetEntity.position.offset(0, targetEntity.height * 0.8, 0);
      await bot.lookAt(aimPos, true);
      await sleep(50);
    }

    if (checkStatus()) {
      bot.deactivateItem(); // Release the arrow
      await sleep(200); // Cooldown/reset
    }
  }

  bot.pathfinder.setGoal(null);
});

return "<RANGED_ATTACK>: Starting bow attack on " + (targetEntity.name || "target") + " while maintaining distance of " + args.preferredDistance + ".";
